"use client";

import { Check, X } from "lucide-react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Slider } from "@/components/ui/slider";
import { Switch } from "@/components/ui/switch";

const fadingBorderStyle = `
  relative before:absolute before:inset-0 before:border before:border-gray-700 before:rounded-lg
  before:bg-gradient-to-b before:from-gray-700 before:to-transparent before:opacity-50
  before:pointer-events-none
`;

export function PricingPageComponent() {
  const [logEntries, setLogEntries] = useState(1000000);
  const [isApplicationLogs, setIsApplicationLogs] = useState(true);

  const calculatePrice = (entries: number) => {
    return Math.round(entries / 10000);
  };

  return (
    <div className="min-h-screen bg-black p-8 text-white">
      <div className="mx-auto max-w-6xl">
        <div className="mb-8 flex justify-center space-x-4">
          <Switch checked={isApplicationLogs} onCheckedChange={() => setIsApplicationLogs(true)} />
          <span className={isApplicationLogs ? "font-bold" : ""}>Application Logs</span>
          <Switch
            checked={!isApplicationLogs}
            onCheckedChange={() => setIsApplicationLogs(false)}
          />
          <span className={!isApplicationLogs ? "font-bold" : ""}>Infrastructure Logs</span>
        </div>

        <div className="grid grid-cols-1 gap-8 md:grid-cols-3">
          {/* Free Tier */}
          <div className={`flex flex-col p-6 ${fadingBorderStyle}`}>
            <h2 className="mb-4 text-2xl font-bold">Free</h2>
            <div className="mb-6 text-4xl font-bold tabular-nums">$0 / mo</div>
            <div className="mb-6">
              <div>Up to 50,000 log entries / mo</div>
              <div className="text-sm text-gray-400">1,000 log entries / day</div>
            </div>
            <div className="flex-grow space-y-2">
              <Feature included>Basic Log Search</Feature>
              <Feature included>1 Team Member</Feature>
              <Feature included>1-day Log Retention</Feature>
              <Feature included>Email Alerts</Feature>
              <Feature>Advanced Analytics</Feature>
              <Feature>Custom Dashboards</Feature>
              <Feature>24/7 Support</Feature>
            </div>
            <Button className="mt-6 w-full">Get started</Button>
          </div>

          {/* Pro Tier */}
          <div className={`flex flex-col p-6 ${fadingBorderStyle}`}>
            <h2 className="mb-4 text-2xl font-bold">Pro</h2>
            <div className="mb-6 text-4xl font-bold tabular-nums">
              ${calculatePrice(logEntries)} / mo
            </div>
            <div className="mb-6">
              <Slider
                min={100000}
                max={5000000}
                step={100000}
                value={[logEntries]}
                onValueChange={(value) => value[0] && setLogEntries(value[0])}
              />
              <div>
                <span className="tabular-nums">{logEntries.toLocaleString()}</span> log entries / mo
              </div>
              <div className="text-sm text-gray-400">No daily sending limit</div>
            </div>
            <div className="flex-grow space-y-2">
              <Feature included>Advanced Log Search</Feature>
              <Feature included>Unlimited Team Members</Feature>
              <Feature included>30-day Log Retention</Feature>
              <Feature included>Email & Slack Alerts</Feature>
              <Feature included>Advanced Analytics</Feature>
              <Feature included>Custom Dashboards</Feature>
              <Feature>24/7 Support</Feature>
            </div>
            <Button className="mt-6 w-full">Get started</Button>
          </div>

          {/* Enterprise Tier */}
          <div className={`flex flex-col p-6 ${fadingBorderStyle}`}>
            <h2 className="mb-4 text-2xl font-bold">Enterprise</h2>
            <div className="mb-6 text-4xl font-bold">Custom</div>
            <div className="mb-6">
              <div>A plan based on your specific needs</div>
              <div className="text-sm text-gray-400">No log entry limits</div>
            </div>
            <div className="flex-grow space-y-2">
              <Feature included>Advanced Log Search</Feature>
              <Feature included>Unlimited Team Members</Feature>
              <Feature included>Customizable Log Retention</Feature>
              <Feature included>Custom Alert Integrations</Feature>
              <Feature included>Advanced Analytics</Feature>
              <Feature included>Custom Dashboards</Feature>
              <Feature included>24/7 Priority Support</Feature>
            </div>
            <Button className="mt-6 w-full">Contact us</Button>
          </div>
        </div>
      </div>
    </div>
  );
}

function Feature({
  children,
  included = false,
}: {
  children: React.ReactNode;
  included?: boolean;
}) {
  return (
    <div className="flex items-center space-x-2">
      {included ? (
        <Check className="h-5 w-5 text-green-500" />
      ) : (
        <X className="h-5 w-5 text-gray-500" />
      )}
      <span className={included ? "" : "text-gray-500"}>{children}</span>
    </div>
  );
}

import { Check, Sparkles } from "lucide-react";
import type React from "react";
import { Link } from "@/components/primitives/link";
import { Button, buttonVariants } from "@/components/ui/button";
import { Card, CardContent, CardFooter, CardHeader } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import type { PricingPlan } from "@/content/pricing/pricing-content";
import { cn } from "@/lib/utils";

interface PricingSectionSingleProps {
  plans?: PricingPlan[];
  plan?: PricingPlan;
  children?: React.ReactNode;
}

export function PricingSectionSingle({ plans, plan, children }: PricingSectionSingleProps) {
  // Use the provided single plan, or the first plan from the plans array
  const selectedPlan = plan || (plans?.length ? plans[0] : null);

  if (!selectedPlan) {
    return null;
  }

  const price =
    selectedPlan.price.monthly || selectedPlan.price.annually || selectedPlan.price.oneTime || 0;

  return (
    <div className="relative w-full text-white">
      {/* Background gradient effect */}
      <div className="container mx-auto p-4">
        <Card className="relative mx-auto max-w-3xl overflow-hidden border-purple-500/50 backdrop-blur-sm transition-shadow duration-300 hover:shadow-xl hover:shadow-purple-500/10">
          <div className="absolute inset-0 bg-gradient-to-br from-purple-500/10 via-transparent to-transparent" />
          <div className="absolute -right-32 -top-32 h-64 w-64 rounded-full bg-purple-500/10 blur-[100px]" />

          <CardHeader className="relative space-y-4 p-8 text-center sm:p-12">
            <div className="flex items-center justify-center gap-2">
              <h2 className="text-3xl font-bold sm:text-4xl">{selectedPlan.title}</h2>
              {selectedPlan.isBestValue && <Sparkles className="h-6 w-6 text-purple-400" />}
            </div>

            <div className="space-y-2">
              <div className="flex items-center justify-center gap-3">
                <span className="text-5xl font-bold sm:text-6xl">${price}</span>
              </div>
              {selectedPlan.description && (
                <div className="border-gray-800 pt-8 text-center text-sm text-gray-400">
                  <p>{selectedPlan.description}</p>
                </div>
              )}
            </div>
          </CardHeader>
          <CardContent className="relative space-y-8 p-8 sm:p-12">
            <Separator />

            <div className="grid gap-6 sm:grid-cols-2">
              {selectedPlan.features.map((feature) => (
                <div key={feature} className="flex items-center gap-2">
                  <Check className="h-5 w-5 shrink-0 text-purple-400" />
                  <span className="text-base">{feature}</span>
                </div>
              ))}
            </div>

            <div className="pt-4">
              {selectedPlan.isComingSoon ? (
                <Button
                  disabled
                  className={cn("w-full bg-purple-500 text-lg text-white hover:bg-purple-600")}
                >
                  Coming Soon
                </Button>
              ) : (
                <Link
                  href={selectedPlan.href}
                  className={cn(
                    buttonVariants({ variant: "default" }),
                    "w-full bg-purple-500 text-lg text-white transition-all duration-200 hover:bg-purple-600 hover:scale-[1.02] active:scale-[0.98]"
                  )}
                >
                  Get {selectedPlan.title} Now
                </Link>
              )}
            </div>
          </CardContent>
          {children && (
            <CardFooter className="relative flex flex-col gap-4">
              <Separator />
              {children}
            </CardFooter>
          )}
        </Card>
      </div>
    </div>
  );
}
